INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (0.0, "カオリ（サマー）", 24, 4, "2019/07/31 12:00:00", 4, 24015, 1, "あうぅ～残念さ～\nマジムンに魂を\n奪われちゃったかな～？", 0.0, "2030/12/17 14:59:59", 10021, 0.0, 110501);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (0.0, "カオリ（サマー）", 24, 1, "2019/07/31 12:00:00", 4, 24016, 2, "今日は踊りのキレも悪いよ～\nゴーヤーっぽいもの食べて、元気回復さ～！", 4.0, "2030/12/17 14:59:59", 10021, 0.0, 110501);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (0.0, "カオリ（サマー）", 24, 4, "2019/07/31 12:00:00", 4, 24017, 3, "マジムンだらけで目が回るさ～！\nふらふらさ～！", 0.0, "2030/12/17 14:59:59", 10021, 0.0, 110501);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (0.0, "カオリ（サマー）", 24, 2, "2019/07/31 12:00:00", 1, 24018, 4, "なんくるない、なんくるない\n次、頑張ればいいんだよ～！\n海で泳いで\nリフレッシュするさー！", 5.2, "2030/12/17 14:59:59", 10021, 0.0, 110501);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (0.0, "カオリ（サマー）", 24, 6, "2019/07/31 12:00:00", 5, 24019, 5, "恥ずかしいところ\n見られちゃったね～\n水着？　水着のことじゃないよー？", 4.2, "2030/12/17 14:59:59", 10021, 0.0, 110501);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (0.0, "カオリ（サマー）", 24, 2, "2019/07/31 12:00:00", 2, 24020, 6, "絶好調さ～！　この調子で\n海の平和を取り戻すよ～！\n楽しい夏が待ってるさ～！", 0.0, "2030/12/17 14:59:59", 10021, 0.0, 110501);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (0.0, "カオリ（サマー）", 24, 6, "2019/07/31 12:00:00", 1, 24021, 7, "何匹で襲ってきたって\n私はマブイを落っことさないよ～！\nくしゅん！　あ……\n今のくしゃみで落っこちたかも～？", 6.4, "2030/12/17 14:59:59", 10021, 0.0, 110501);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (0.0, "カオリ（サマー）", 24, 2, "2019/07/31 12:00:00", 2, 24022, 8, "ひーやーさーさー♪\n戦いの後は、踊りを踊って\n気分スッキリさ～！", 0.0, "2030/12/17 14:59:59", 10021, 0.0, 110501);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (0.0, "カオリ（サマー）", 24, 3, "2019/07/31 12:00:00", 6, 24023, 9, "あれ～？　戦ってるうちに\n水着がどっか行っちゃった～？\nねぇキミ、どっかで見なかった～？\nなんで離れるさ～？", 10.08, "2030/12/17 14:59:59", 10021, 0.0, 110501);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (0.0, "カオリ（サマー）", 24, 2, "2019/07/31 12:00:00", 1, 24024, 10, "まだまだ私は元気だよ～！\nマジムンでもなんでも、\nどんとこーいさー♪", 5.0, "2030/12/17 14:59:59", 10021, 0.0, 110501);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (0.0, "カオリ（サマー）", 24, 2, "2019/07/31 12:00:00", 2, 24025, 11, "私の空手は世界最強さ～！\n夏の陽射しと青い海も合わされば、\n向かうところ敵なしだよー！", 0.0, "2030/12/17 14:59:59", 10021, 0.0, 110501);
